play.autodarts.io.css:
:root {
  --color-bg-main: rgba(20, 20, 20, 0.9);
  --color-bg-box: linear-gradient(145deg, rgba(45, 45, 45, 0.9), rgba(10, 10, 10, 0.95));
  --color-border-inactive: rgba(180, 160, 120, 0.4);
  
  /* Goldgelb-Palette für den aktiven Spieler */
  --active-gold: #ffcc00; 
  --active-gold-bright: #ffe500;
  --active-gold-glow: rgba(255, 204, 0, 0.7);
  
  --color-text: #f5f5f0;
  --font-main: 'Montserrat', sans-serif;
  --spacing-player: 20px;
  --row-height-3: calc((108% - 180px) / 3 - var(--spacing-player));
}

/* --- FORCE ANIMATION LOGIC --- */
@keyframes goldGlowPulse {
  0% { 
    box-shadow: 0 0 15px var(--active-gold-glow) !important; 
    border-color: var(--active-gold) !important;
    transform: scale(1.03);
  }
  50% { 
    box-shadow: 0 0 45px var(--active-gold), inset 0 0 15px rgba(255,255,255,0.2) !important; 
    border-color: #ffffff !important;
    transform: scale(1.05);
  }
  100% { 
    box-shadow: 0 0 15px var(--active-gold-glow) !important; 
    border-color: var(--active-gold) !important;
    transform: scale(1.03);
  }
}

/* --- Globaler Hintergrund --- */
body {
  background-image: url(https://i.ibb.co/qLrdmYGc/bg.jpg) !important;
  background-size: cover !important;
  background-position: center !important;
  background-attachment: fixed !important;
}

/* --- Spielerboxen Basis (Inaktiv) --- */
:root:not(:has(.css-rc3vw3)) .css-rtn29s,
:root:not(:has(.css-rc3vw3)) .css-hjw8x4 {
  background: var(--color-bg-box) !important;
  color: var(--color-text) !important;
  border: 1px solid var(--color-border-inactive);
  backdrop-filter: blur(10px);
  border-radius: 12px;
  position: absolute;
  width: 400px;
  height: calc((100% - 180px) / 3);
  transition: all 0.3s ease-in-out;
}

/* --- AKTIVER SPIELER: GOLDGELB & PULSIEREND --- */
/* Wir nutzen mehrere Selektoren, um sicherzugehen, dass Autodarts den Style nicht überschreibt */
:root:not(:has(.css-rc3vw3)) .css-rtn29s, 
[class*="active-player"], 
.ad-ext-player.active {
  z-index: 100 !important;
  background: linear-gradient(145deg, #2a2a00, #000000) !important; /* Dunkles Gold-Schwarz für Kontrast */
  border: 3px solid var(--active-gold) !important;
  animation: goldGlowPulse 1.5s infinite ease-in-out !important;
}

/* Texte beim aktiven Spieler */
:root:not(:has(.css-rc3vw3)) .css-rtn29s .css-1j0bqop,
:root:not(:has(.css-rc3vw3)) .css-rtn29s .css-1r7jzhg {
  color: var(--active-gold) !important;
  text-shadow: 0 0 12px rgba(255, 204, 0, 0.8) !important;
  font-weight: 900 !important;
}

/* --- Scoring Bereich --- */
:root:not(:has(.css-rc3vw3)) #ad-ext-turn .css-rrf7rv,
:root:not(:has(.css-rc3vw3)) #ad-ext-turn .score.css-156dsds,
:root:not(:has(.css-rc3vw3)) #ad-ext-turn .ad-ext-turn-throw.css-1p5spmi {
  background: rgba(15, 15, 15, 0.9) !important;
  border: 1px solid var(--color-border-inactive);
  border-radius: 10px;
  height: 120px;
  color: #fff !important;
}

/* --- Layout-Positionierung (1-6 Spieler) --- */
/* 1-2 Spieler */
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(1):only-child { top: 90px; left: 60px; height: calc(100% - 180px); }
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(1):nth-last-child(2) { top: 90px; left: 60px; height: calc(100% - 200px); }
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(2):nth-last-child(1) { top: 90px; right: 60px; height: calc(100% - 200px); }

/* 3-4 Spieler */
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(1):nth-last-child(3),
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(1):nth-last-child(4) { top: 90px; left: 60px; height: calc((105% - 180px) / 2 - var(--spacing-player)); }
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(2):nth-last-child(2),
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(2):nth-last-child(3) { top: 90px; right: 60px; height: calc((105% - 180px) / 2 - var(--spacing-player)); }
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(3):nth-last-child(1),
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(3):nth-last-child(2) { top: calc(90px + ((100% - 180px) / 2) + var(--spacing-player)); left: 60px; height: calc((105% - 180px) / 2 - var(--spacing-player)); }
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(4):last-child { top: calc(90px + ((100% - 180px) / 2) + var(--spacing-player)); right: 60px; height: calc((105% - 180px) / 2 - var(--spacing-player)); }

/* 5-6 Spieler */
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(1):nth-last-child(5),
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(1):nth-last-child(6) { top: 90px; left: 60px; height: var(--row-height-3); }
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(2):nth-last-child(4),
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(2):nth-last-child(5) { top: 90px; right: 60px; height: var(--row-height-3); }
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(3):nth-last-child(3),
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(3):nth-last-child(4) { top: calc(90px + ((100% - 180px) / 3) + var(--spacing-player)); left: 60px; height: var(--row-height-3); }
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(4):nth-last-child(2),
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(4):nth-last-child(3) { top: calc(90px + ((100% - 180px) / 3) + var(--spacing-player)); right: 60px; height: var(--row-height-3); }
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(5):nth-last-child(1),
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(5):nth-last-child(2) { top: calc(90px + 2 * ((100% - 180px) / 3) + 2 * var(--spacing-player)); left: 60px; height: var(--row-height-3); }
:root:not(:has(.css-rc3vw3)) #ad-ext-player-display > div:nth-child(6):last-child { top: calc(90px + 2 * ((100% - 180px) / 3) + 2 * var(--spacing-player)); right: 60px; height: var(--row-height-3); }

/* Menüs & Badges */
span.chakra-badge.css-n2903v {
  font-size: 20px;
  color: var(--active-gold) !important;
  background: rgba(0,0,0,0.6) !important;
}

[id^="menu-list-"] {
  background: #111 !important;
  border: 1px solid var(--active-gold) !important;
  border-radius: 12px;
}
